#include<bits/stdc++.h>
using namespace std;
int n,m,x,y,a[1005][1005],ans=0;
int dx[]={1,0,-1,0};
int dy[]={0,1,0,-1};
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    cin>>x>>y;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(a[i][j]==x){
                for(int k=0;k<4;k++){
                    int mx=i+dx[k];
                    int my=j+dy[k];
                    if(mx<=0||my<=0||mx>n||my>m){
                        continue;
                    }
                    if(a[mx][my]==y){
                        ans++;
                        break;
                    }
                }
            }
        }
    }
    cout<<ans;
}
